import { useEffect, useState } from "react";
import axios from "axios";

function Users(){

    const [users,setUsers] = useState([]);

    useEffect(()=>{
        axios.get("http://localhost:3000/users")
        .then(res=>{
            setUsers(res.data);
        })
    },[])

    return(
        <div>
            <h2>Danh sách Users</h2>

            <ul>
                {users.map(user=>(
                    <li key={user.id}>
                        {user.id} - {user.name}
                    </li>
                ))}
            </ul>

        </div>
    )
}

export default users;
